    "html": "<div class=\"tooltip-container\">\n  <div class=\"tooltip\">\n    <div class=\"text\">Save Trees</div>\n\n    <div class=\"leaf leaf1\"></div>\n    <div class=\"leaf leaf2\"></div>\n    <div class=\"leaf leaf3\"></div>\n    <div class=\"leaf leaf4\"></div>\n  </div>\n  <div class=\"leaf icon\"></div>\n</div>",
    "css": "/* From Uiverse.io by Lakshay-art  - Tags: simple, tooltip, animation, green, shadow, realistic, creative, savetrees */\n/* This is an example, feel free to delete this code */\n.tooltip-container {\n  /* --background: #22d3ee; */\n  position: relative;\n  background: var(--background);\n  cursor: pointer;\n  transition: all 0.2s;\n  font-size: 17px;\n  padding: 0.7em 1.8em;\n  margin-bottom: -100px;\n}\n\n.bg {\n  position: absolute;\n  left: -30px;\n  top: 0px;\n  z-index: -2;\n}\n\n.tooltip {\n  position: absolute;\n  top: 0;\n  left: 50%;\n  width: 180px;\n  height: 100px;\n  transform: translateX(-50%);\n  padding: 0.5em 1em;\n  opacity: 0;\n  pointer-events: none;\n  transition: all 0.3s;\n  background: url(\"data:image/jpeg;base64,\");\n  border-radius: 30px;\n  background-size: cover;\n  box-shadow: inset 0px 8px 9px #182218, 5px 8px 0px #314328;\n  filter: drop-shadow(60px 60px 6px #18221888);\n  border: 10px solid #3f5641ee;\n  z-index: -1;\n  animation: float 2s infinite;\n}\n\n.tooltip::before {\n  position: absolute;\n  content: \"\";\n  height: 20px;\n  width: 20px;\n  bottom: -22px;\n  left: 50%;\n  transform: translate(-50%) rotate(45deg);\n  background: #e9f6f4;\n  border: 10px solid #3f5641ee;\n  border-left: none;\n  border-top: none;\n  border-radius: 5px;\n  box-shadow: 10px 4px 0px #314328;\n}\n\n.tooltip-container:hover .tooltip {\n  top: -120px;\n  opacity: 1;\n  visibility: visible;\n  pointer-events: auto;\n}\n\n.leaf1 {\n  top: -30px;\n  left: -60px;\n}\n.leaf2 {\n  top: -30px;\n  left: -60px;\n}\n.leaf3 {\n  top: -30px;\n  left: -60px;\n}\n.leaf4 {\n  top: -30px;\n  left: -60px;\n}\n.tooltip-container:hover .leaf1 {\n  rotate: z 20deg;\n}\n/* .tooltip-container:hover .leaf2{\nrotate: z 20deg;\n} */\n.tooltip-container:hover .leaf3 {\n  rotate: z -20deg;\n}\n.tooltip-container:hover .leaf4 {\n  rotate: z 40deg;\n}\n\n.leaf {\n  width: 60px;\n  height: 40px;\n  position: absolute;\n  transform-origin: 100% 100%;\n  transition: rotate 0.5s 0.2s linear;\n  /* border: px solid #314328; */\n  border-radius: 0 100%;\n  background-image: linear-gradient(to right, #b4c7b3, #314328);\n}\n.icon {\n  /* box-shadow: 60px 60px 6px #18221888,120px 60px 6px #18221888; */\n  transform: translateX(-50%);\n  filter: drop-shadow(60px 60px 6px #18221888);\n}\n.text {\n  z-index: 2;\n  font-size: 22px;\n  color: #3f5641;\n  font-weight: bolder;\n  margin: auto;\n  width: fit-content;\n  padding-top: 25px;\n  filter: drop-shadow(0px 0px 3px #fff);\n}\n@keyframes float {\n  0% {\n    top: -120px;\n  }\n  50% {\n    top: -125px;\n  }\n  100% {\n    top: -120px;\n  }\n}"
